mapper.select:
SELECT a.ITLK_ID, a.ITLK_NM, a.ITLK_STM_NM, a.ITLK_MTHD_CLS_CD, b.CD_NM AS ITLK_MTHD_CLS_NM, a.ITLK_YN, a.USE_YN, a.ITLK_EXPL, a.RLTM_UPD_SEND_YN, NVL(a.FIR_VAL_ITLK_YN,'N') FIR_VAL_ITLK_YN, a.DEL_YN, a.API_KEY_VAL, a.BAT_DB_URL, a.BAT_DB_ID, a.BAT_DB_PWD, a.BAT_SQL, a.BAT_DVLP_JOB_ID, a.STM_FIR_REG_USER_ID, (SELECT NVL(MAX(c.USER_NM),'manual') FROM AD_USER_MST c WHERE c.USER_ID = a.STM_FIR_REG_USER_ID) STM_FIR_REG_USER_NM, TO_CHAR(a.STM_FIR_REG_DATE,'YYYY.MM.DD HH24:MI') STM_FIR_REG_DATE, a.STM_LAST_UPD_USER_ID, (SELECT NVL(MAX(d.USER_NM),'manual') FROM AD_USER_MST d WHERE d.USER_ID = a.STM_LAST_UPD_USER_ID) STM_LAST_UPD_USER_Nm, TO_CHAR(a.STM_LAST_UPD_DATE,'YYYY.MM.DD HH24:MI') STM_LAST_UPD_DATE FROM PM_ITLK_RSC_MST a, AD_COMM_CD b WHERE 1=1 AND a.ITLK_MTHD_CLS_CD = b.COMM_CD AND a.DEL_YN = 'N' AND b.COMM_GRP_CD = 'ITLK_MTHD_CLS_CD'
AND UPPER(a.ITLK_NM) LIKE '%'||UPPER(#{itlkNm})||'%'
AND UPPER(a.ITLK_STM_NM) LIKE '%'||UPPER(#{itlkStmNm})||'%'
AND a.ITLK_MTHD_CLS_CD IN
#{value}
AND a.ITLK_YN = #{itlkYn}
AND a.USE_YN = #{useYn}
ORDER BY a.STM_LAST_UPD_DATE DESC, a.ITLK_NM
